//#region Types/Modal/ModalInterop.ts
var scrollLockCount = 0;
var focusTrapStack = [];
var activeTabHandler = null;
var FOCUSABLE_SELECTORS = [
	"button:not([disabled])",
	"[href]",
	"input:not([disabled])",
	"select:not([disabled])",
	"textarea:not([disabled])",
	"[tabindex]:not([tabindex=\"-1\"])",
	"[contenteditable=\"\"]",
	"[contenteditable=\"true\"]",
	"audio[controls]",
	"video[controls]",
	"iframe",
	"embed",
	"object"
].join(", ");
function lockScroll() {
	scrollLockCount++;
	if (scrollLockCount === 1) document.body.style.overflow = "hidden";
}
function unlockScroll() {
	scrollLockCount--;
	if (scrollLockCount <= 0) {
		scrollLockCount = 0;
		document.body.style.overflow = "";
	}
}
function trapFocus(element, id) {
	const previousActiveElement = document.activeElement;
	const focusables = element.querySelectorAll(FOCUSABLE_SELECTORS);
	let firstFocusable = null;
	let lastFocusable = null;
	if (focusables.length === 0) {
		element.setAttribute("tabindex", "-1");
		element.focus();
	} else {
		firstFocusable = focusables[0];
		lastFocusable = focusables[focusables.length - 1];
		firstFocusable.focus();
	}
	focusTrapStack.push({
		id,
		previousActiveElement,
		container: element,
		firstFocusable,
		lastFocusable
	});
	if (!activeTabHandler) {
		activeTabHandler = (e) => {
			if (e.key !== "Tab") return;
			const top = focusTrapStack[focusTrapStack.length - 1];
			if (!top) return;
			const active = document.activeElement;
			const { container, firstFocusable: first, lastFocusable: last } = top;
			if (!active || !container.contains(active)) {
				if (first) {
					e.preventDefault();
					first.focus();
				}
				return;
			}
			if (!first || !last) return;
			if (e.shiftKey) {
				if (active === first) {
					e.preventDefault();
					last.focus();
				}
			} else if (active === last) {
				e.preventDefault();
				first.focus();
			}
		};
		document.addEventListener("keydown", activeTabHandler);
	}
}
function waitForAnimationEnd(element, fallbackMs) {
	if (!element) return Promise.resolve();
	if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) return Promise.resolve();
	return new Promise((resolve) => {
		let done = false;
		const finish = () => {
			if (done) return;
			done = true;
			element.removeEventListener("animationend", finish);
			element.removeEventListener("transitionend", finish);
			clearTimeout(timeoutId);
			resolve();
		};
		element.addEventListener("animationend", finish, { once: true });
		element.addEventListener("transitionend", finish, { once: true });
		const timeoutId = window.setTimeout(finish, fallbackMs);
	});
}
function releaseFocus(id) {
	const idx = focusTrapStack.findIndex((s) => s.id === id);
	if (idx === -1) return;
	const wasTop = idx === focusTrapStack.length - 1;
	const [released] = focusTrapStack.splice(idx, 1);
	if (focusTrapStack.length === 0 && activeTabHandler) {
		document.removeEventListener("keydown", activeTabHandler);
		activeTabHandler = null;
	}
	if (wasTop && released.previousActiveElement) released.previousActiveElement.focus();
}
//#endregion
export { lockScroll, releaseFocus, trapFocus, unlockScroll, waitForAnimationEnd };